// Enhanced ModelLoader with better debugging and error handling

import * as THREE from 'three';
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader';
import { DRACOLoader } from 'three/examples/jsm/loaders/DRACOLoader';
export class ModelLoader {
  constructor() {
    // Initialize loaders with verbose logging
    this.gltfLoader = new GLTFLoader();
    console.log("GLTFLoader initialized");

    // Add DRACO decoder for compressed models
    this.dracoLoader = new DRACOLoader();
    // Use the default Draco CDN or provide your own path
    this.dracoLoader.setDecoderPath('https://www.gstatic.com/draco/versioned/decoders/1.5.6/');
    this.dracoLoader.setDecoderConfig({
      type: 'js'
    }); // Use JS decoder for wider compatibility
    this.gltfLoader.setDRACOLoader(this.dracoLoader);
    console.log("DRACOLoader initialized");

    // Model cache to avoid reloading the same models
    this.modelCache = new Map();

    // Set up verbose loading manager
    this.loadingManager = new THREE.LoadingManager(
    // onLoad
    () => {
      console.log('Loading complete!');
    },
    // onProgress
    (url, loaded, total) => {
      const progress = Math.floor(loaded / total * 100);
      console.log(`Loading file: ${url} - ${progress}% loaded`);
    },
    // onError
    url => {
      console.error(`Error loading: ${url}`);
    });
    this.gltfLoader.manager = this.loadingManager;
  }

  /**
   * Load a model with enhanced error handling and logging
   * @param {string} modelType - Type of model from the catalogue
   * @param {string} modelPath - Path to the GLB file
   * @param {Function} callback - Function to call with the loaded model
   */
  load(modelType, modelPath, callback) {
    console.log(`Loading model: ${modelType} from path: ${modelPath}`);

    // Check if path is valid
    if (!modelPath) {
      console.error(`Invalid model path for model type: ${modelType}`);
      this.createPlaceholderModel(modelType, callback);
      return;
    }

    // Check if model is already cached
    if (this.modelCache.has(modelPath)) {
      console.log(`Using cached model for: ${modelType}`);
      const cachedModel = this.modelCache.get(modelPath);
      const clonedModel = this.cloneModel(cachedModel);
      callback(clonedModel);
      return;
    }

    // Load the model with more detailed logging
    console.log(`Starting GLB file load for: ${modelPath}`);
    this.gltfLoader.load(modelPath, gltf => {
      try {
        console.log(`Successfully loaded GLTF for: ${modelType}`, gltf);

        // Log model structure to help with debugging
        console.log(`Model structure for ${modelType}:`, this.describeGltf(gltf));

        // Process and prepare the model
        const model = this.processLoadedModel(gltf, modelType);

        // Cache the model for future use
        this.modelCache.set(modelPath, model.clone());

        // Call the callback with the model
        callback(model);
      } catch (err) {
        console.error(`Error processing model ${modelType}:`, err);
        this.createPlaceholderModel(modelType, callback);
      }
    },
    // Progress callback
    xhr => {
      const percent = Math.round(xhr.loaded / xhr.total * 100);
      console.log(`${modelType} ${percent}% loaded`);
    },
    // Error callback
    error => {
      console.error(`Error loading model ${modelType} from ${modelPath}:`, error);
      this.createPlaceholderModel(modelType, callback);
    });
  }

  /**
   * Create a description of the GLTF structure for debugging
   * @param {Object} gltf - The loaded GLTF object
   * @returns {Object} - Description of the GLTF structure
   */
  describeGltf(gltf) {
    const description = {
      animations: gltf.animations ? gltf.animations.length : 0,
      scenes: gltf.scenes ? gltf.scenes.length : 0,
      cameras: gltf.cameras ? gltf.cameras.length : 0,
      asset: gltf.asset,
      sceneInfo: {}
    };

    // Describe the scene structure
    if (gltf.scene) {
      let meshCount = 0;
      let materialCount = 0;
      let textureCount = 0;
      const meshes = [];
      gltf.scene.traverse(node => {
        if (node.isMesh) {
          meshCount++;
          meshes.push({
            name: node.name || `UnnamedMesh${meshCount}`,
            geometry: {
              vertices: node.geometry.attributes.position ? node.geometry.attributes.position.count : 'unknown',
              faces: node.geometry.index ? node.geometry.index.count / 3 : 'unknown'
            },
            material: node.material ? node.material.name || 'Unnamed Material' : 'No Material'
          });
        }
        if (node.material) materialCount++;
        if (node.material && node.material.map) textureCount++;
      });
      description.sceneInfo = {
        meshCount,
        materialCount,
        textureCount,
        meshes: meshes.slice(0, 5) // Show first 5 meshes only for brevity
      };
    }
    return description;
  }

  /**
   * Create a placeholder model when loading fails
   * @param {string} modelType - Type of model
   * @param {Function} callback - Function to call with the placeholder model
   */
  createPlaceholderModel(modelType, callback) {
    console.log(`Creating placeholder for: ${modelType}`);

    // Create dimensions based on model type
    // These dimensions would normally come from a configuration file
    const dimensions = {
      width: 1,
      height: 0.5,
      depth: 1
    };

    // Create a simple box geometry
    const geometry = new THREE.BoxGeometry(dimensions.width, dimensions.height, dimensions.depth);

    // Create a material with a random color
    const material = new THREE.MeshStandardMaterial({
      color: Math.random() * 0xffffff,
      roughness: 0.7,
      metalness: 0.2
    });

    // Create the mesh
    const mesh = new THREE.Mesh(geometry, material);
    mesh.castShadow = true;
    mesh.receiveShadow = true;

    // Create a group to hold the mesh
    const group = new THREE.Group();
    group.add(mesh);

    // Position it so bottom is at y=0
    mesh.position.y = dimensions.height / 2;

    // Add model type to userData
    group.userData.type = modelType;
    group.userData.isModelRoot = true;
    group.userData.isPlaceholder = true;

    // Add a label with the model type (for visualization)
    this.addPlaceholderLabel(group, `${modelType} (placeholder)`);
    console.log(`Placeholder created for: ${modelType}`);
    callback(group);
  }

  /**
   * Add a text label to placeholder models
   * @param {THREE.Group} group - The group to add the label to
   * @param {string} text - The text to display
   */
  addPlaceholderLabel(group, text) {
    // Create a canvas for the texture
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.width = 256;
    canvas.height = 64;

    // Draw background
    context.fillStyle = '#ffffff';
    context.fillRect(0, 0, canvas.width, canvas.height);

    // Draw text
    context.font = 'bold 18px Arial';
    context.fillStyle = '#000000';
    context.textAlign = 'center';
    context.textBaseline = 'middle';
    context.fillText(text, canvas.width / 2, canvas.height / 2);

    // Create texture from canvas
    const texture = new THREE.CanvasTexture(canvas);

    // Create a plane geometry for the label
    const labelGeometry = new THREE.PlaneGeometry(1, 0.25);
    const labelMaterial = new THREE.MeshBasicMaterial({
      map: texture,
      side: THREE.DoubleSide,
      transparent: true
    });

    // Create the label mesh
    const label = new THREE.Mesh(labelGeometry, labelMaterial);

    // Position the label above the model
    label.position.y = 0.5;
    label.position.z = 0.25;
    label.rotation.x = -Math.PI / 4;

    // Add to the group
    group.add(label);
  }

  /**
   * Process a loaded GLTF model
   * @param {Object} gltf - The loaded GLTF object
   * @param {string} modelType - Type of model
   * @returns {THREE.Object3D} - Processed model
   */
  processLoadedModel(gltf, modelType) {
    const model = gltf.scene;

    // Log warning if model has no meshes
    let hasMeshes = false;
    model.traverse(node => {
      if (node.isMesh) {
        hasMeshes = true;
      }
    });
    if (!hasMeshes) {
      console.warn(`Model ${modelType} has no meshes!`);
    }

    // Add shadow casting to all meshes
    model.traverse(node => {
      if (node.isMesh) {
        console.log(`Processing mesh: ${node.name || 'unnamed'} for model: ${modelType}`);
        node.castShadow = true;
        node.receiveShadow = true;

        // Check and fix materials if needed
        if (!node.material) {
          console.warn(`Mesh ${node.name || 'unnamed'} has no material, adding default`);
          node.material = new THREE.MeshStandardMaterial({
            color: 0xcccccc,
            roughness: 0.7,
            metalness: 0.2
          });
        }

        // Optimize materials if needed
        this.optimizeMaterial(node.material);
      }
    });

    // Set model properties
    model.userData.type = modelType;
    model.userData.isModelRoot = true;

    // Center model on its base
    this.centerModel(model);
    console.log(`Model processing complete for: ${modelType}`);
    return model;
  }

  /**
   * Center the model on its base
   * @param {THREE.Object3D} model - The model to center
   */
  centerModel(model) {
    // Calculate bounding box
    const bbox = new THREE.Box3().setFromObject(model);
    const center = new THREE.Vector3();

    // Get dimensions
    bbox.getCenter(center);
    const width = bbox.max.x - bbox.min.x;
    const height = bbox.max.y - bbox.min.y;
    const depth = bbox.max.z - bbox.min.z;
    console.log(`Model dimensions:`, {
      width,
      height,
      depth
    });

    // Center horizontally, place bottom at y=0
    model.position.x = -center.x;
    model.position.y = -bbox.min.y;
    model.position.z = -center.z;

    // Store actual dimensions in userData
    model.userData.actualDimensions = {
      width,
      height,
      depth
    };
  }

  /**
   * Optimize material for better performance
   * @param {THREE.Material} material - Material to optimize
   */
  optimizeMaterial(material) {
    if (!material) return;

    // If it's an array of materials, optimize each one
    if (Array.isArray(material)) {
      material.forEach(mat => this.optimizeMaterial(mat));
      return;
    }

    // Set reasonable defaults for better performance
    if (material.map) {
      console.log(`Optimizing texture: ${material.map.name || 'unnamed'}`);
      material.map.anisotropy = 4; // Improve texture quality with reasonable performance
    }

    // Check for common material issues
    if (material.color && material.color.r === 0 && material.color.g === 0 && material.color.b === 0) {
      console.warn(`Material has black color, adjusting to light gray`);
      material.color.set(0xcccccc);
    }
  }

  /**
   * Clone a model with its materials and textures
   * @param {THREE.Object3D} model - The model to clone
   * @returns {THREE.Object3D} - Cloned model
   */
  cloneModel(model) {
    if (!model) return null;
    const clone = model.clone();

    // Clone materials to avoid shared materials between instances
    clone.traverse(node => {
      if (node.isMesh && node.material) {
        if (Array.isArray(node.material)) {
          node.material = node.material.map(mat => mat.clone());
        } else {
          node.material = node.material.clone();
        }
      }
    });

    // Clone userData
    clone.userData = JSON.parse(JSON.stringify(model.userData));
    return clone;
  }

  /**
   * Test if a model file exists and is accessible
   * @param {string} url - URL to test
   * @returns {Promise<boolean>} - Whether the file exists
   */
  async testModelFile(url) {
    try {
      const response = await fetch(url, {
        method: 'HEAD'
      });
      return response.ok;
    } catch (error) {
      console.error(`Error testing model file at ${url}:`, error);
      return false;
    }
  }
}

