        console.log(`Processing mesh: ${node.name || 'unnamed'} for model: ${modelType}`);
        node.castShadow = true;
        node.receiveShadow = true;
        
        // Check and fix materials if needed
        if (!node.material) {
          console.warn(`Mesh ${node.name || 'unnamed'} has no material, adding default`);
          node.material = new THREE.MeshStandardMaterial({
            color: 0xcccccc,
            roughness: 0.7,
            metalness: 0.2
          });
        }
        
        // Optimize materials if needed
        this.optimizeMaterial(node.material);
      }
    });
    
    // Set model properties
    model.userData.type = modelType;
    model.userData.isModelRoot = true;
    
    // Center model on its base
    this.centerModel(model);
    
    console.log(`Model processing complete for: ${modelType}`);
    return model;
  }
  
  /**
   * Center the model on its base
   * @param {THREE.Object3D} model - The model to center
   */
  centerModel(model) {
    // Calculate bounding box
    const bbox = new THREE.Box3().setFromObject(model);
    const center = new THREE.Vector3();
    
    // Get dimensions
    bbox.getCenter(center);
    const width = bbox.max.x - bbox.min.x;
    const height = bbox.max.y - bbox.min.y;
    const depth = bbox.max.z - bbox.min.z;
    
    console.log(`Model dimensions:`, { width, height, depth });
    
    // Center horizontally, place bottom at y=0
    model.position.x = -center.x;
    model.position.y = -bbox.min.y;
    model.position.z = -center.z;
    
